#include <bits/stdc++.h>
using namespace std;
const int N=500005;
int tim,dfn[N],low[N],cnt,vis[N],n,m,vis2[N],vis3[N],a[N],flag[N],ans,s,s2,p,dp[N],fir[N],from[N],to[N],cnt2,fir2[N],from2[N],to2[N],cnt3;
stack<int> st;
bool flag2[N];
void add(int a,int b)
{
    from[++cnt2]=fir[a];
    fir[a]=cnt2; to[cnt2]=b;
}
void add2(int a,int b)
{
    from2[++cnt3]=fir2[a];
    fir2[a]=cnt3; to2[cnt3]=b;
}
void tarjan(int u)
{
	dfn[u]=low[u]=++tim;
	st.push(u);
	for(int i=fir[u];i;i=from[i])
    {
		int v=to[i];
		if(dfn[v]==0)
        {
			tarjan(v);
			low[u]=min(low[u],low[v]);
		}
		else if(vis[v]==0)
        {
			low[u]=min(low[u],dfn[v]);
		}
	}
	if(low[u]==dfn[u])
    {
		cnt++;
		while(true)
        {
			int now=st.top();
			st.pop();
			vis[now]=cnt;
            vis2[cnt]+=a[now];
            if(now==s) s2=cnt;
            if(flag[now]) vis3[cnt]=1;
			if(now==u) break;
		}
	}
}
void topo()
{
	queue<int> q;
    q.push(s2);
    while(!q.empty())
    {
        int v=q.front();
        q.pop();
        flag2[v]=0;
        if(v==s2) dp[v]=vis2[v];
        for(int i=fir2[v];i;i=from2[i])
        {
            int j=to2[i];
            if(flag2[j]==0)
            {
                q.push(j);
                flag2[j]=1;
            }
            dp[j]=max(dp[j],dp[v]+vis2[j]);
        }
        if(vis3[v]) ans=max(ans,dp[v]);
    }
}
int main()
{
    cin>>n>>m;
    for(int i=1;i<=m;i++)
    {
        int u,v;
        cin>>u>>v;
        add(u,v);
    }
    for(int i=1;i<=n;i++)
    {
        cin>>a[i];
    }
    cin>>s>>p;
    for(int i=1;i<=p;i++)
    {
        int x;
        cin>>x;
        flag[x]=1;
    }
	tarjan(s);
	for(int u=1;u<=n;u++)
    {
        if(vis[u]==0) continue;
		for(int i=fir[u];i;i=from[i])
        {
            int j=to[i];
            if(vis[j]==0) continue;
			if(vis[u]!=vis[j])
            {
                add2(vis[u],vis[j]);
			}
		}
	}
    topo();
    cout<<ans;
	return 0;
}
